+func (sm *SpringManager) GetDimension(id string) (width, height int) {
+	if sm == nil || id == "" {
+		return 0, 0
+	}
+	w := sm.Get(id + ":w")
+	h := sm.Get(id + ":h")
+	return int(math.Round(w)), int(math.Round(h))
