+	sm.SetWithParams(id+":scroll", float64(offset), 8.0, 0.5)
+}
+
+// GetScrollOffset returns the current animated scroll position.
+func (sm *SpringManager) GetScrollOffset(id string) int {
+	if sm == nil || id == "" {
+		return 0
+	}
+	return int(math.Round(sm.Get(id + ":scroll")))
+}

